	memset(vis,0,sizeof(vis));
	memset(dist,0,sizeof(dist));
	queue<int> q;
	q.push(source);
	int last=source;
	while(!q.empty()){
		int front=q.front(); 
		q.pop();
		if(vis[front]) continue;
		last=front;
		for(auto i : g[front]){
			if(vis[i]) continue;
			dist[i]=dist[front]+1;
			q.push(i);
		}
	}
	return last;
}
