use std::collections::{HashMap, HashSet};

/// Longest path in a DAG using topological sort.
fn longest_path(adj_list: &HashMap<i32, Vec<(i32, i32)>>, start_node: i32) -> HashMap<i32, f64> {
    let num_nodes = adj_list.len() as i32;
    let mut visited = HashSet::new();
    let mut topo_order = Vec::new();

    fn dfs(
        adj_list: &HashMap<i32, Vec<(i32, i32)>>,
        node: i32,
        visited: &mut HashSet<i32>,
        topo_order: &mut Vec<i32>,
    ) {
        visited.insert(node);
        if let Some(neighbors) = adj_list.get(&node) {
            for &(v, _) in neighbors {
                if !visited.contains(&v) {
                    dfs(adj_list, v, visited, topo_order);
                }
            }
        }
        topo_order.push(node);
    }

    for i in 0..num_nodes {
        if !visited.contains(&i) {
            dfs(adj_list, i, &mut visited, &mut topo_order);
        }
    }

    let mut dist = vec![f64::NEG_INFINITY; num_nodes as usize];
    dist[start_node as usize] = 0.0;

    for i in (0..topo_order.len()).rev() {
        let u = topo_order[i];
        let ui = u as usize;
        if dist[ui] != f64::NEG_INFINITY {
            if let Some(neighbors) = adj_list.get(&u) {
                for &(v, w) in neighbors {
                    let vi = v as usize;
                    if dist[ui] + w as f64 > dist[vi] {
                        dist[vi] = dist[ui] + w as f64;
                    }
                }
            }
        }
    }

    let mut result = HashMap::new();
    for i in 0..num_nodes {
        result.insert(i, dist[i as usize]);
    }
    result
}

fn main() {
    let mut adj_list = HashMap::new();
    adj_list.insert(0, vec![(1, 3), (2, 6)]);
    adj_list.insert(1, vec![(3, 4), (2, 4)]);
    adj_list.insert(2, vec![(3, 2)]);
    adj_list.insert(3, vec![]);

    let result = longest_path(&adj_list, 0);
    println!("Longest distances: {:?}", result);
}

import scala.collection.mutable

/**
 * Longest path in a DAG using topological sort.
 */
object LongestPath {
  def longestPath(adjList: Map[Int, List[(Int, Int)]], startNode: Int): Map[Int, Double] = {
    val numNodes = adjList.size
    val visited = mutable.Set[Int]()
    val topoOrder = mutable.ListBuffer[Int]()

    def dfs(node: Int): Unit = {
      visited.add(node)
      for ((v, _) <- adjList.getOrElse(node, List.empty)) {
        if (!visited.contains(v)) dfs(v)
      }
      topoOrder += node
    }

    for (i <- 0 until numNodes) {
      if (!visited.contains(i)) dfs(i)
    }

    val dist = Array.fill(numNodes)(Double.NegativeInfinity)
    dist(startNode) = 0.0

    for (i <- topoOrder.indices.reverse) {
      val u = topoOrder(i)
      if (dist(u) != Double.NegativeInfinity) {
        for ((v, w) <- adjList.getOrElse(u, List.empty)) {
          if (dist(u) + w > dist(v)) {
            dist(v) = dist(u) + w
          }
        }
      }
    }

    (0 until numNodes).map(i => i -> dist(i)).toMap
  }

  def main(args: Array[String]): Unit = {
    val adjList = Map(
      0 -> List((1, 3), (2, 6)),
      1 -> List((3, 4), (2, 4)),
      2 -> List((3, 2)),
      3 -> List()
    )

    val result = longestPath(adjList, 0)
    println(s"Longest distances: $result")
  }
}

/// Longest path in a DAG using topological sort.
func longestPath(adjList: [Int: [[Int]]], startNode: Int) -> [Int: Double] {
    let numNodes = adjList.count
    var visited = Set<Int>()
    var topoOrder = [Int]()

    func dfs(_ node: Int) {
        visited.insert(node)
        if let neighbors = adjList[node] {
            for edge in neighbors {
                if !visited.contains(edge[0]) {
                    dfs(edge[0])
                }
            }
        }
        topoOrder.append(node)
    }

    for i in 0..<numNodes {
        if !visited.contains(i) {
            dfs(i)
        }
    }

    var dist = [Double](repeating: -Double.infinity, count: numNodes)
    dist[startNode] = 0

    for i in stride(from: topoOrder.count - 1, through: 0, by: -1) {
        let u = topoOrder[i]
        if dist[u] != -Double.infinity {
            if let neighbors = adjList[u] {
                for edge in neighbors {
                    let v = edge[0]
                    let w = Double(edge[1])
                    if dist[u] + w > dist[v] {
                        dist[v] = dist[u] + w
                    }
                }
            }
        }
    }

    var result = [Int: Double]()
    for i in 0..<numNodes {
        result[i] = dist[i]
    }
    return result
}

